#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate the area of a polygon using the Shoelace formula
long long calculateArea(int n, int *x, int *y) {
    long long area = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += (long long)x[i] * y[j] - (long long)x[j] * y[i];
    }
    return abs(area) / 2;
}

// Function to check if a point is inside a polygon
int isInside(int n, int *x, int *y, int px, int py) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        if (y[i] > py) {
            if (y[j] <= py && (x[j] - x[i]) * (py - y[i]) / (y[j] - y[i]) + x[i] > px) {
                count++;
            }
        } else if (y[i] <= py) {
            if (y[j] > py && (x[j] - x[i]) * (py - y[i]) / (y[j] - y[i]) + x[i] > px) {
                count++;
            }
        }
    }
    return count % 2 == 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *x = (int *)malloc(n * sizeof(int));
        int *y = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        int needles = 0;
        int pins = 0;
        for (int i = 0; i < m; i++) {
            int x1, y1, x2, y2;
            scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
            int dx = x2 - x1;
            int dy = y2 - y1;
            int gcd = gcd(abs(dx), abs(dy));
            dx /= gcd;
            dy /= gcd;
            int currX = x1;
            int currY = y1;
            while (currX != x2 || currY != y2) {
                if (isInside(n, x, y, currX, currY)) {
                    needles++;
                }
                currX += dx;
                currY += dy;
            }
            if (isInside(n, x, y, currX, currY)) {
                needles++;
            }
        }
        long long area = calculateArea(n, x, y);
        pins = area - needles;
        printf("%d %d\n", needles, pins);
    }
    return 0;
}

int gcd(int a, int b) {
    if (b == 0) {
        return a;
    }
    return gcd(b, a % b);
}

